import {
  collection,
  getDocs,
  addDoc,
  deleteDoc,
  doc,
  updateDoc,
  serverTimestamp,
  orderBy,
  query,
} from "firebase/firestore";
import { db } from "../firebase";

async function fetchCollection(collectionName, orderField) {
  try {
    const q = orderField
      ? query(collection(db, collectionName), orderBy(orderField, "asc"))
      : collection(db, collectionName);
    const snapshot = await getDocs(q);
    return snapshot.docs.map((d) => ({ id: d.id, ...d.data() }));
  } catch (error) {
    console.error(`Error fetching ${collectionName}:`, error);
    return [];
  }
}

// ── Knowledge Base ──────────────────────────────────────────────

export const getPolicies = () => fetchCollection("knowledge_base");

export const addPolicy = async (title, content, category) => {
  try {
    await addDoc(collection(db, "knowledge_base"), {
      title,
      content,
      category,
      createdAt: serverTimestamp(),
    });
    return true;
  } catch (error) {
    console.error("Error adding policy:", error);
    return false;
  }
};

export const updatePolicy = async (id, title, content, category) => {
  try {
    await updateDoc(doc(db, "knowledge_base", id), { title, content, category });
    return true;
  } catch (error) {
    console.error("Error updating policy:", error);
    return false;
  }
};

export const deletePolicy = async (id) => {
  try {
    await deleteDoc(doc(db, "knowledge_base", id));
    return true;
  } catch (error) {
    console.error("Error deleting policy:", error);
    return false;
  }
};

